const Q_PHYSICS_2021_MODEL_I=[{"id": "objective>Physics>2021 Model I>1", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The work function of a metal is given to be 3.31 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">40</span>J. The threshold frequency is  <br/> [h = 6.62 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-34</span>Js]</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">5.0 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">73</span>Hz</div>", "<div style=\"font-family:Cambria;font-size:17px;\">5.0 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">75</span>Hz</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2.0 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">73</span>Hz</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2.0 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">75</span>Hz</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Workfunction, W<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">o</span> = 3.31 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">40</span>J <br/> Threshold frequency, f<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">o</span> = ? <br/> Planck's constant, h = 6.62 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-34</span>Js <br/> Recall, W<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">o</span> = hf<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">o</span> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">f<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">o</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">W<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">o</span><hr size=\"1\" />h</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">3.31 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">40</span><hr size=\"1\" />6.62 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-34</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">5.0</td><td style=\"text-align:center;\">x</td><td style=\"text-align:center;\">10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">73</span>Hz</td></tr></table></div></div>", "topic": "ELEMENTARY MODERN PHYSICS : EINSTEIN’S EQUATION AND STOPPING POTENTIAL"}, {"id": "objective>Physics>2021 Model I>2", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is used to slow down fast moving neutrons in a nuclear reactor?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Concrete shield </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Boron rods </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Carbondioxide gas </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Graphite block </div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Graphite bricks serve as a neutron moderator i.e they help to reduce the speed of neutrons and allow a nuclear reaction to be sustained. <br/> Boron rods serve as neutron poison. They help to absorb neutrons in order to prevent further fission.</div>", "topic": "ELEMENTARY MODERN PHYSICS : FUSION AND FISSION"}, {"id": "objective>Physics>2021 Model I>3", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Determine the supplied current in the circuit diagram below. <br/>  <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/></div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">0.4A</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.5A</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.6A</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.8A</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">6Ω is parallel to 3Ω <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">1<hr size=\"1\" />R<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />6</td><td style=\"text-align:center;\">+</td><td style=\"text-align:center;\">1<hr size=\"1\" />3</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">1<hr size=\"1\" />R<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">3<hr size=\"1\" />6</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">1<hr size=\"1\" />R<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1 + 2<hr size=\"1\" />6</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">R<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">6<hr size=\"1\" />3</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">2Ω</td></tr></table></div> <br/> 2Ω is in series with 4Ω <br/> R<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = 2Ω + 4Ω = 6Ω <br/> 6Ω(R<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>) is parallel to 6Ω <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">1<hr size=\"1\" />R<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />6</td><td style=\"text-align:center;\">+</td><td style=\"text-align:center;\">1<hr size=\"1\" />6</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">1<hr size=\"1\" />R<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1 + 1<hr size=\"1\" />6</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">1<hr size=\"1\" />R<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">2<hr size=\"1\" />6</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">R<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">6<hr size=\"1\" />2</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">3Ω</td></tr></table></div> <br/> R<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> is in series with R<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span> i.e 2Ω is in series with 3Ω <br/> Effective resistance, R = 2Ω + 3Ω = 5Ω <br/> Recall, V = IR <br/> 3 = I × 5 <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">I</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">3<hr size=\"1\" />5</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">0.6A</td></tr></table></div></div>", "topic": "CURRENT ELECTRICITY : OHM’S LAW~~CURRENT ELECTRICITY : RESISTANCE IN SERIES AND IN PARALLEL"}, {"id": "objective>Physics>2021 Model I>4", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is not correct for an AC circuit in a state of resonance?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Z = R</div>", "<div style=\"font-family:Cambria;font-size:17px;\">cosθ = 1</div>", "<div style=\"font-family:Cambria;font-size:17px;\">V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">L</span> = V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">C</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">θ = 90°</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The following happen at resonance. <br/> i) Maximum current is obtained from the circuit <br/> ii) Power factor, cosθ = 1 i.e θ = 0° <br/> iii) Capacitive reactance is equal to inductive reactance i.e X<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">c</span> =X<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">L</span> <br/> iv) The voltage across the capacitor is equal to the voltage across the inductor i.e V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">C</span> = V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">L</span> <br/> v) The impedance is equal to the resistance of the resistor i.e Z = R <br/> </div>", "topic": "SIMPLE A. C. CIRCUITS : RESONANCE AND RESONANCE FREQUENCY"}, {"id": "objective>Physics>2021 Model I>5", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A body of mass 2.5kg and density 5000kg/m<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> is fully immersed in water. The upthrust experienced by the body is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">2.5N</div>", "<div style=\"font-family:Cambria;font-size:17px;\">5.0N</div>", "<div style=\"font-family:Cambria;font-size:17px;\">7.5N</div>", "<div style=\"font-family:Cambria;font-size:17px;\">10.0N</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">According to Archimedes principle, when an object is partially or fully immersed in a fluid, it experiences an upthrust which is equal to the weight of fluid displaced. <br/> Upthrust = Weight of water displaced  <br/> Weight = mass × acceleration due to gravity <br/> W<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">w</span> = M<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">w</span>g <br/> Upthrust = M<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">w</span>g <br/> Recall, <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">Density,</td><td style=\"text-align:center;\">ρ</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">mass, m<hr size=\"1\" />volume, v</td></tr></table></div> <br/> U = ρ<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">w</span>V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">w</span>g <br/> ρ<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">w</span> = 1000kg/m<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> <br/> Volume of water = Volume of solid immersed, V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">s</span> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">ρ<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">s</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">M<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">s</span><hr size=\"1\" />V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">s</span></td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">s</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">M<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">s</span><hr size=\"1\" />ρ<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">s</span></td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">∴</td><td style=\"text-align:center;\">Upthrust</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">ρ<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">w</span></td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">M<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">s</span><hr size=\"1\" />ρ<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">s</span></td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">g</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1000</td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">2.5<hr size=\"1\" />5000</td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">10</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">∴</td><td style=\"text-align:center;\">Upthrust</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">25<hr size=\"1\" />5</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">5.0N</td></tr></table></div></div>", "topic": "LIQUIDS AT REST : ARCHIMEDE’S PRINCIPLE"}, {"id": "objective>Physics>2021 Model I>6", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The depth of a fish below the river is displaced by 2.4cm. If the refractive index of water is 4/3, the real depth of the fish in the river is _____</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">4.8cm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">7.2cm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">9.6cm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">3.6cm</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">displacement, d = 2.4cm <br/> refractive index, n = 4/3 <br/> Recall, <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">n</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">real depth r<hr size=\"1\" />apparent depth, a</td></tr></table></div> <br/> real depth, r = apparent depth, a + displacement, d <br/> r = a + d <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">n</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">a + d<hr size=\"1\" />a</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">n</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1</td><td style=\"text-align:center;\">+</td><td style=\"text-align:center;\">d<hr size=\"1\" />a</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">4<hr size=\"1\" />3</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1</td><td style=\"text-align:center;\">+</td><td style=\"text-align:center;\">2.4<hr size=\"1\" />a</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">4<hr size=\"1\" />3</td><td style=\"text-align:center;\">-</td><td style=\"text-align:center;\">1</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">2.4<hr size=\"1\" />a</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">1<hr size=\"1\" />3</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">2.4<hr size=\"1\" />a</td></tr></table></div> <br/> a = 7.2cm <br/> r = 7.2 + 2.4 <br/> r = 9.6cm</div>", "topic": "REFRACTION OF LIGHT THROUGH : PLANE AND CURVED SURFACE"}, {"id": "objective>Physics>2021 Model I>7", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A dry cleaner uses electric iron for 5 weeks at an average of 8 hrs per day. The power rating of its iron is 1200W. How much will he be charged if a unit of electricity costs ₦3.10K?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">₦917.60K</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦1041.60K</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦850.50K</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦1551.30K</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Energy, E = Power, P × time, t <br/> E = Pt [which is measured in KWh] <br/> P = 1200W  <br/> t = 8 x 5 x 7 = 280hrs <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">P</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1200<hr size=\"1\" />1000</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1.2KW</td></tr></table></div> <br/> E = 1.2 X 280 = 336 KWh <br/> 1 unit = 1KWh = ₦3.10K <br/> 1KWh = ₦3.10K <br/> 336KWh = x <br/> He will be charged ₦1041.60k</div>", "topic": "ELECTRICAL ENERGY AND POWER : COMMERCIAL UNIT OF ELECTRIC ENERGY AND POWER"}, {"id": "objective>Physics>2021 Model I>8", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The silvered wall inside a vacuum flask is to prevent heat loss by</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">conduction</div>", "<div style=\"font-family:Cambria;font-size:17px;\">convection</div>", "<div style=\"font-family:Cambria;font-size:17px;\">radiation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">evaporation</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Heat transfer by radiation doesn't require material medium. Shining, silvered or polished surfaces are good reflectors of heat. Hence, the silvered wall in the vacuum flask reflects heat which prevents or minimizes heat loss by radiation.</div>", "topic": "HEAT TRANSFER : THERMOS FLASK"}, {"id": "objective>Physics>2021 Model I>9", "question": "<div style=\"font-family:Cambria;font-size:17px;\">What is the magnitude of frictional force exerted on an object of mass 6.0kg on an inclined plane which makes angle 60° to the horizontal if the coefficient of kinetic friction is 0.3.? [g = 10ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span>]</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">18.0N</div>", "<div style=\"font-family:Cambria;font-size:17px;\">12.0N</div>", "<div style=\"font-family:Cambria;font-size:17px;\">9.0N</div>", "<div style=\"font-family:Cambria;font-size:17px;\">5.0N</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"> <img src=\"2021 Model I/phy2.png\" style=\"position:relative;max-width:100%;\"/> <br/> Frictional force, F = ? <br/> Normal reaction, R = mgcosθ = 6 × 10cos60° = 30N <br/> Coefficient of kinetic friction, μ = 0.3 <br/> Recall, F = μR (from the law of solid friction) <br/> F = 0.3 x 30 <br/> F = 9.0N</div>", "topic": "FRICTION"}, {"id": "objective>Physics>2021 Model I>10", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An object of height 9cm is placed in front of a pinhole camera of size 6cm. How far is the object from the pinhole if the image formed is 3cm high?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">8cm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">12cm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">15cm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">18cm</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Object height, U<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">H</span> = 9cm <br/> Image distance (length of camera), V = 6cm <br/> Object distance, U = ? <br/> Image height, V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">H</span> = 3cm <br/> Recall,  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">V<hr size=\"1\" />U</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">H</span><hr size=\"1\" />U<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">H</span></td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">6<hr size=\"1\" />U</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">3<hr size=\"1\" />9</td></tr></table></div> <br/> 6 x 9 = 3 x U <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">U</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">6 x 9<hr size=\"1\" />3</td></tr></table></div> <br/> U = 18cm <br/> </div>", "topic": "LIGHT ENERGY : PROPAGATION OF LIGHT"}, {"id": "objective>Physics>2021 Model I>11", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The tyre pressure of a car was found to be 150cmHg in the morning at a temperature of 27°C. Hard driving in the afternoon raised the temperature of the tyre to 57°C. The tyre pressure in the afternoon has </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">increased by 15.0cmHg</div>", "<div style=\"font-family:Cambria;font-size:17px;\">decreased by 15.0cmHg</div>", "<div style=\"font-family:Cambria;font-size:17px;\">increased by 22.5cmHg</div>", "<div style=\"font-family:Cambria;font-size:17px;\">decreased by 22.50cmHg</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Initial pressure, P<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> = 150cmHg <br/> Initial temperature, T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> = 27°C = 27°C + 273 = 300K <br/> Final pressure, P<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = ? <br/> Final temperature, T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = 57°C = 273 + 57 = 330K <br/> From Pressure law, <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">P<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span><hr size=\"1\" />T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">P<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span><hr size=\"1\" />T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">150<hr size=\"1\" />300</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">P<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span><hr size=\"1\" />330</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">P<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">150 x 330<hr size=\"1\" />300</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">165cmHg</td></tr></table></div> <br/> Since the new pressure is 165cmHg, then the pressure has increased by 15.0cmHg</div>", "topic": "GAS LAWS"}, {"id": "objective>Physics>2021 Model I>12", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A boiler of resistance 20Ω is used to change the temperature of 2kg of water from 15°c to 75°C. How long will it take the boiler if the supplied current is 6A? [S.H.C of water = 4200JKg<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>K<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>]</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">12 mins 10secs </div>", "<div style=\"font-family:Cambria;font-size:17px;\">13 mins 5 secs </div>", "<div style=\"font-family:Cambria;font-size:17px;\">11 min 40 secs </div>", "<div style=\"font-family:Cambria;font-size:17px;\">10 min 50 secs </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Electrical heat, E = I<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>Rt <br/> I<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>Rt = mcΔθ <br/> 6<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> × 20 × t = 2 × 4200 (75 - 15) <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">t</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">2 x 4200 x 60<hr size=\"1\" />36 x 20</td></tr></table></div> <br/> t = 700secs = 11min 40secs</div>", "topic": "QUANTITY OF HEAT : HEAT CAPACITY AND SPECIFIC HEAT CAPACITY"}, {"id": "objective>Physics>2021 Model I>13", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Two bodies of the same mass experience a force of attraction 2.82 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-7</span> N when placed at a distance of 100cm in a gravitational field. Determine their mass [G = 6.67 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-11</span>Nm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>Kg<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span>]</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">65kg</div>", "<div style=\"font-family:Cambria;font-size:17px;\">70kg</div>", "<div style=\"font-family:Cambria;font-size:17px;\">75kg</div>", "<div style=\"font-family:Cambria;font-size:17px;\">82kg</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Force, F = 2.82 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-7</span>N <br/> Distance, r = 100cm = 1m <br/> m<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> = m<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = m (mass) <br/> From Newton's law of universal gravitation, <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">F</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">GM<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>M<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span><hr size=\"1\" />r<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span></td><td style=\"text-align:center;\">(but</td><td style=\"text-align:center;\">M<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">M<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>)</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">F</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">GM<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span><hr size=\"1\" />r<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span></td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">2.82</td><td style=\"text-align:center;\">x</td><td style=\"text-align:center;\">10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-7</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">6.67x10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-11</span>M<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span><hr size=\"1\" />1<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span></td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">M<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">2.82 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-7</span><hr size=\"1\" />6.67 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-11</span></td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">M</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">&radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\">&nbsp;</span></td><td style=\"text-align:center;\">2.82 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-7</span><hr size=\"1\" />6.67 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-11</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">65kg</td></tr></table></div></div>", "topic": "GRAVITATIONAL FIELD"}, {"id": "objective>Physics>2021 Model I>14", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following statements is not correct <br/> I. Kaleidoscope works on the principle of inclination of mirrors <br/> II. Galvanometer works on the principle of rotation of mirror <br/> III. A parabolic mirror will be free from spherical aberration</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">I and II only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">I and III only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">All of the above </div>", "<div style=\"font-family:Cambria;font-size:17px;\">None of the above</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A kaleidoscope is an optical instrument used to produce colourful pattern. It operates based on the inclination of plane mirrors. <br/> A mirror galvanometer is an optical instrument which operates based on rotational of mirror. <br/> Optical aberration occurs when reflected rays from a spherical mirror do not pass through the principal focus. This is corrected using parabolic mirror. <br/> Looking at the combination of the other options, none of them answers the question correctly. <br/>  <br/> It can also be noted that moving coil galvanometer which is also called galvanometer also makes use of mirror</div>", "topic": "REFLECTION OF LIGHT AT PLANE AND CURVED SURFACES"}, {"id": "objective>Physics>2021 Model I>15", "question": "<div style=\"font-family:Cambria;font-size:17px;\">When a negatively charged rod is brought near the cap of a negatively charged gold-leaf electroscope, the leaves will</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">collapse </div>", "<div style=\"font-family:Cambria;font-size:17px;\">diverge more </div>", "<div style=\"font-family:Cambria;font-size:17px;\">become positively charged </div>", "<div style=\"font-family:Cambria;font-size:17px;\">negatively charged </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A negatively charged gold-leaf electroscope has divergent leaves since both leaves posses negative charges. The negative charges make the leaves to diverge due to repulsion. When a negatively charged rod is brought near the cap of the electroscope, the negative charges in the rod repel the negative charges in the cap to the leaves, which leads to further divergence of the leaves.</div>", "topic": "ELECTROSTATICS : ELECTROSCOPE"}, {"id": "objective>Physics>2021 Model I>16", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following consists entirely of vector quantities?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Velocity, magnetic flux and reaction.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">tension, magnetic flux and mass </div>", "<div style=\"font-family:Cambria;font-size:17px;\">displacement, impulse and power </div>", "<div style=\"font-family:Cambria;font-size:17px;\">work, pressure and moment</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Velocity, magnetic flux density, reaction, tension, displacement, impulse and moment are vector quantities while mass, power, work, pressure and magnetic flux are scalar quantities. Vectors are quantities with both magnitude and direction while scalars have only magnitude without direction.</div>", "topic": "SCALARS AND VECTORS"}, {"id": "objective>Physics>2021 Model I>17", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A current of 2.4A flowing through a wire of length 60cm in a field of 0.1T. The maximum force experienced by the wire is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">0.144N</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.44N</div>", "<div style=\"font-family:Cambria;font-size:17px;\">14.4N</div>", "<div style=\"font-family:Cambria;font-size:17px;\">144N</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Current, I = 2.4A <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">length,</td><td style=\"text-align:center;\">l</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">60cm</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">60<hr size=\"1\" />100</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">0.6m</td></tr></table></div> <br/> Magnetic flux density, B = 0.1T <br/> Angle, θ = 90° (For maximum force) <br/> Recall, <br/> F = BILsinθ <br/> F = 0.1 x 2.4 x 0.6sin90° <br/> F = 0.144N</div>", "topic": "FORCE ON A CURRENT-CARRYING CONDUCTOR IN A MAGNETIC FIELD"}, {"id": "objective>Physics>2021 Model I>18", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of these is a second order lever?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Wheel barrow </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Plier</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Sugar tong</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Scissors </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A second order lever is an order of lever in which the load is between the fulcrum and the effort. Examples are wheelbarrow, nutcracker, bottle opener. Plier and scissors are first order lever while sugar tong is a third order lever.</div>", "topic": "SIMPLE MACHINES"}, {"id": "objective>Physics>2021 Model I>19", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A wave is represented by the equation y = 0.2sin[0.4π(x - 60t)], where x and y are in cm and t is in s. The velocity of the wave is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">120cms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">60cms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">24cms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">4.8cms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">y = 0.2sin[0.4π(x - 60t)] <br/> compare with a suitable progressive wave equation <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">y</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">Asin2π<hr size=\"1\" />λ</td><td style=\"text-align:center;\">(x</td><td style=\"text-align:center;\">-</td><td style=\"text-align:center;\">vt)</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">y</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">Asin(</td><td style=\"text-align:center;\">2π<hr size=\"1\" />λ</td><td style=\"text-align:center;\">(x</td><td style=\"text-align:center;\">-</td><td style=\"text-align:center;\">vt)</td><td style=\"text-align:center;\">)</td></tr></table></div> <br/> ∴ vt = 60t <br/> Hence, velocity, v = 60cms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "topic": "WAVES : PRODUCTION AND PROPAGATION"}, {"id": "objective>Physics>2021 Model I>20", "question": "<div style=\"font-family:Cambria;font-size:17px;\">I. Tension <br/> II. Length <br/> III. Mass <br/> Which of the above has a direct relationship with frequency of a vibrating string?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">I only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">I and II only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">II and III only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">II only </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Frequency, f, length, l, tension, T and mass per unit length, μ are related <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">f</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />2l</td><td style=\"text-align:center;\">&radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\"></td><td style=\"text-align:center;\">T<hr size=\"1\" />μ</td><td style=\"text-align:center;\">&nbsp;</span></td></tr></table></div> <br/> Frequency is inversely proportional to length i.e f α 1/l <br/> Frequency is directly proportional to square root of tension i.e f α &radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\">T&nbsp;</span> <br/> It is only tension that has direct relationship with frequency.</div>", "topic": "PROPAGATION OF SOUND WAVES"}, {"id": "objective>Physics>2021 Model I>21", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> From the above, the polarity of X and Y ends of the magnets are  </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">North and North</div>", "<div style=\"font-family:Cambria;font-size:17px;\">North and South</div>", "<div style=\"font-family:Cambria;font-size:17px;\">South and North</div>", "<div style=\"font-family:Cambria;font-size:17px;\">South and South </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">One of the properties of magnetic lines of force is that \"they originate from the north pole and terminate at the south pole\". The magnetic lines of force actually originate from X and Y. Hence, they are both north poles.</div>", "topic": "MAGNETS AND MAGNETIC FIELDS"}, {"id": "objective>Physics>2021 Model I>22", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A body of mass 500g is undergoing a circular motion with a velocity of 36km/hr with a radius of 40cm. The centripetal force on the body is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">125N</div>", "<div style=\"font-family:Cambria;font-size:17px;\">250N</div>", "<div style=\"font-family:Cambria;font-size:17px;\">375N</div>", "<div style=\"font-family:Cambria;font-size:17px;\">500N</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">Mass,</td><td style=\"text-align:center;\">m</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">500g</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">500<hr size=\"1\" />1000</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">0.5kg</td></tr></table></div> <br/> Velocity, v = 36km/hr <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\"></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">36x1000<hr size=\"1\" />60x60</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">10m/s</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">radius,</td><td style=\"text-align:center;\">r</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">40cm</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">40<hr size=\"1\" />100</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">0.4m</td></tr></table></div> <br/> Centripetal force, F = ? <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">F</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">mv<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span><hr size=\"1\" />r</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">F</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">0.5 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span><hr size=\"1\" />0.4</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">125N</td></tr></table></div></div>", "topic": "MOTION: MOTION IN A CIRCLE"}, {"id": "objective>Physics>2021 Model I>23", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In Fleming's right-hand rule, the thumb, the fore-finger and the middle finger if held mutually at right angles represent respectively, the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">motion, the field and the induced current</div>", "<div style=\"font-family:Cambria;font-size:17px;\">induced current, the motion and the field </div>", "<div style=\"font-family:Cambria;font-size:17px;\">field, the induced current and the motion</div>", "<div style=\"font-family:Cambria;font-size:17px;\">induced current, the field and the motion</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Fleming's Left-hand rule is mainly applicable to electric motor while Fleming's right hand rule is mainly for electric generators. <br/> Fleming's right hand rule states that if the thumb, the fore finger and the second fingers of the right hand are at right angles to one another, the fore finger points in the direction of the field, the second finger points the direction of the current, then the thumb points in the direction of motion of conductor.</div>", "topic": "ELECTROMAGNETIC INDUCTION : A.C. AND D.C GENERATORS"}, {"id": "objective>Physics>2021 Model I>24", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A new thermometer was constructed which measures temperature in degree Mellow (°M). The lower and upper fixed points are -20°M and 200°M respectively. The equivalent of 150°M in Kelvin is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">320K</div>", "<div style=\"font-family:Cambria;font-size:17px;\">330K</div>", "<div style=\"font-family:Cambria;font-size:17px;\">340K</div>", "<div style=\"font-family:Cambria;font-size:17px;\">350K</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The lower and upper fixed points in kelvin scale are 273K and 373K respectively. <br/>  <img src=\"2021 Model I/phy4.png\" style=\"position:relative;max-width:100%;\"/> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">150 - (-20)<hr size=\"1\" />200 - (-20)</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">θ-273<hr size=\"1\" />373 - 273</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">150 + 20<hr size=\"1\" />200 + 20</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">θ - 273<hr size=\"1\" />100</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">170<hr size=\"1\" />200 + 20</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">θ - 273<hr size=\"1\" />100</td></tr></table></div> <br/> 170 x 100 = 220(θ - 273) <br/> 17000 = 220θ - 60060 <br/> 77060 = 220θ <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">θ</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">77060<hr size=\"1\" />220</td></tr></table></div> <br/> θ = 350K <br/> </div>", "topic": "TEMPERATURE AND ITS MEASUREMENT"}, {"id": "objective>Physics>2021 Model I>25", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A body of mass 800g starts from rest and accelerates uniformly at 2.5m/s<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>. If a distance of 12.8m is covered. Calculate the kinetic energy gained by the body.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">32.0J</div>", "<div style=\"font-family:Cambria;font-size:17px;\">25.6J</div>", "<div style=\"font-family:Cambria;font-size:17px;\">12.8J</div>", "<div style=\"font-family:Cambria;font-size:17px;\">8.4J</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">mass,</td><td style=\"text-align:center;\">m</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">800g</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">800<hr size=\"1\" />1000</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">0.8kg</td></tr></table></div> <br/> initial velocity, u = 0 ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span> <br/> Final velocity, v = ? <br/> acceleration, a = 2.5m/s<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> <br/> Distance, s = 12.8m <br/> Recall, v<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> = u<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> + 2as <br/> v<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> = 0<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> + 2(2.5)(12.8) <br/> v<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> = 64 <br/> v = &radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\">64&nbsp;</span> = 8m/s <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">Kinetic</td><td style=\"text-align:center;\">energy,</td><td style=\"text-align:center;\">K.E</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />2</td><td style=\"text-align:center;\">mv<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span></td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\"></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />2</td><td style=\"text-align:center;\">x</td><td style=\"text-align:center;\">0.8</td><td style=\"text-align:center;\">x</td><td style=\"text-align:center;\">8<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span></td></tr></table></div> = 0.4 x 64 = 25.6J</div>", "topic": "WORK, ENERGY AND POWER"}, {"id": "objective>Physics>2021 Model I>26", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> A 2kg mass on a smooth inclined plane is connected over a smooth pulley to a 3kg mass as shown in the diagram above. The acceleration of the system is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">g</div>", "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">3g<hr size=\"1\" />4</td></tr></table></div></div>", "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">g<hr size=\"1\" />2</td></tr></table></div></div>", "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">2g<hr size=\"1\" />5</td></tr></table></div></div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"2021 Model I/phy6.png\" style=\"position:relative;max-width:100%;\"/> <br/> 3g > T <br/> 3g - T = 3a <br/> 3g - 3a = T . . . . . (i) <br/> T > 2gsin30° <br/> T - 2gsin30° = 3a <br/> T - 2g(0.5) = 2a <br/> T - g = 2a <br/> T = 2a + g . . . . . . . .. (ii) <br/> Equate (i) and (ii) <br/> T = T <br/> 3g - 3a = 2a + g <br/> 3g - g = 2a + 3a <br/> 2g = 5a <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">2g<hr size=\"1\" />5</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">a</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">a</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">2g<hr size=\"1\" />5</td></tr></table></div> <br/> where T = Tension <br/> a = acceleration </div>", "topic": "MOTION : NEWTON’S LAWS OF MOTION"}, {"id": "objective>Physics>2021 Model I>27", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A rod of length 2m becomes 2.01m when taken from ice to steam. What is its cubic expansivity?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">5.0 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-5</span>K<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.0 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-4</span>K<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.5 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-4</span>K<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">3.0 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-4</span>K<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Initial length, l<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> = 2m <br/> New length, l<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = 2.01m <br/> change in length, Δl = l<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> - l<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> = 2.01m - 2.00m = 0.01m <br/> Initial temperature, θ<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> = 0°C <br/> New temperature, θ<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = 100°C <br/> Linear expansivity, <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">α</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">Δl<hr size=\"1\" />l<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>Δθ</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">α</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">0.01<hr size=\"1\" />2 x (100 - 0)</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">α</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">0.01<hr size=\"1\" />2x100</td></tr></table></div> <br/> α = 5 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-5</span>K<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span> <br/> But cubic expansivity, γ = 3α <br/> γ = 3 x 5 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-5</span>K<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span> <br/> γ = 1.5 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-4</span>K<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "topic": "HEAT TRANSFER~~HEAT TRANSFER: LINEAR EXPANSIVITY"}, {"id": "objective>Physics>2021 Model I>28", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Cylindrical lens is used for the correction of which of these eye defects?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Myopia</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Hypermetropia</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Presbyopia</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Astigmatism</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Myopia (short sightedness) can be corrected using concave lens. <br/> Hypermetropia (Long sightedness) can be corrected using convex lens. <br/> Presbyopia (Loss of accommodation) is corrected for using bifocal lens. <br/> Astigmatism is corrected for using a cylindrical lens.</div>", "topic": "OPTICAL INSTRUMENTS : SIGHT DEFECTS AND THEIR CORRECTIONS"}, {"id": "objective>Physics>2021 Model I>29", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The electrolyte used in a Leclanche cell is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">ZnSO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">CuSO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">MnO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">NH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span>Cl</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A Leclanche cell is a primary cell. Its cathode and anode are carbon and zinc respectively. Its electrolyte is ammonium chloride (NH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span>Cl) while its depolarizer is Manganese IV oxide (MnO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>). <br/> Daniel cell which is also a primary cell has its cathode, anode, electrolyte and depolarizer to be copper, zinc, zinc sulphate (ZnSO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span>) and copper sulphate (CuSO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span>) respectively.</div>", "topic": "ELECTRIC CELLS"}, {"id": "objective>Physics>2021 Model I>30", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The quantity of heat needed to convert a substance in the solid state to liquid is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">latent heat of sublimation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">latent heat of melting </div>", "<div style=\"font-family:Cambria;font-size:17px;\">latent heat of vaporization</div>", "<div style=\"font-family:Cambria;font-size:17px;\">latent heat of fusion</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Latent heat of fusion is the heat required to change a substance in the solid state to liquid without a change in temperature. The heat required to change solid to gas is latent heat of sublimation while heat to change liquid to gas is latent heat of vaporization</div>", "topic": "CHANGE OF STATE : SPECIFIC LATENT HEATS OF FUSION"}, {"id": "objective>Physics>2021 Model I>31", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The temperature at which the saturated vapour pressure in an enclosed liquid is equal to the atmospheric pressure is known as </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">freezing point </div>", "<div style=\"font-family:Cambria;font-size:17px;\">standard temperature </div>", "<div style=\"font-family:Cambria;font-size:17px;\">boiling point </div>", "<div style=\"font-family:Cambria;font-size:17px;\">room temperature</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">When liquid is heated it changes to vapour. The pressure exerted by the vapour when enclosed is called vapour pressure. When the vapour is in contact with its liquid, it is said to be saturated, and the pressure exerted is known as saturated vapour pressure. Liquid boils when its saturated vapour pressure is equal to the atmospheric pressure.</div>", "topic": "CHANGE OF STATE : EVAPORATION AND BOILING"}, {"id": "objective>Physics>2021 Model I>32", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Determine the energy stored in an elastic material whose force constant is 1.2 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">5</span>Nm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span> and extends by 2.0cm</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">24J</div>", "<div style=\"font-family:Cambria;font-size:17px;\">36J</div>", "<div style=\"font-family:Cambria;font-size:17px;\">48J</div>", "<div style=\"font-family:Cambria;font-size:17px;\">72J</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Elastic potential energy, E = ? <br/> Force constant, K = 1.2 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">5</span>Nm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span> <br/> extension, e = 2.0cm = 2/100 = 0.02m <br/> Recall, <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">E</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />2</td><td style=\"text-align:center;\">Ke<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span></td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />2</td><td style=\"text-align:center;\">x</td><td style=\"text-align:center;\">1.2</td><td style=\"text-align:center;\">x</td><td style=\"text-align:center;\">10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">5</span></td><td style=\"text-align:center;\">x</td><td style=\"text-align:center;\">0.02<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span></td></tr></table></div> <br/> E = 24J</div>", "topic": "ELASTICITY : WORK DONE IN SPRINGS AND ELASTIC STRINGS"}, {"id": "objective>Physics>2021 Model I>33", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The mass of copper deposited on the copper voltameter is 450g when a current passed through it for 25minutes. Calculate the current passed through the voltameter. <br/> [Electrochemical equivalent of copper = 3.3 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-4</span>gC<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>]</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">545A</div>", "<div style=\"font-family:Cambria;font-size:17px;\">680A</div>", "<div style=\"font-family:Cambria;font-size:17px;\">909A</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1020A</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">mass, m = 450g <br/> time, t = 25mins = 25 x 60 = 1500s <br/> e.c.e of copper, z = 3.3 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-4</span>gC<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span> <br/> current, I = ? <br/> From Faraday's first law of electrolysis <br/> m = zIt <br/> 450 = 3.3 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-4</span> x I x 1500 <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">I</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">450<hr size=\"1\" />3.3 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-4</span> x 1500</td></tr></table></div> <br/> I = 909A</div>", "topic": "CURRENT ELECTRICITY: ELECTROLYSIS"}, {"id": "objective>Physics>2021 Model I>34", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The diagram shows the velocity-time graph of a vehicle. The distance travelled in exactly half of the total time is  </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">3600m</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2800m</div>", "<div style=\"font-family:Cambria;font-size:17px;\">800m</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2400m</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The area under a velocity-time graph is the distance travelled. Half of the total time is 45s. <br/> <img src=\"2021 Model I/phy8.png\" style=\"position:relative;max-width:100%;\"/> <br/> The shape is a trapezium. <br/> Distance, D = Area of a trapezium <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />2</td><td style=\"text-align:center;\">(a</td><td style=\"text-align:center;\">+</td><td style=\"text-align:center;\">b)h</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />2</td><td style=\"text-align:center;\">(25</td><td style=\"text-align:center;\">+</td><td style=\"text-align:center;\">45)80</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />2</td><td style=\"text-align:center;\">x</td><td style=\"text-align:center;\">70</td><td style=\"text-align:center;\">x</td><td style=\"text-align:center;\">80</td></tr></table></div> <br/> D = 2800m </div>", "topic": "MOTION: LINEAR MOTION"}, {"id": "objective>Physics>2021 Model I>35", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The barometer which functions as an altimeter </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">A mercury barometer </div>", "<div style=\"font-family:Cambria;font-size:17px;\">A fort in barometer </div>", "<div style=\"font-family:Cambria;font-size:17px;\">An aneroid barometer</div>", "<div style=\"font-family:Cambria;font-size:17px;\">A manometer</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A barometer is an instrument used to measure atmospheric pressure. An aneroid barometer is a non liquid barometer. Since pressure varies with height i.e atmospheric pressure decreases with height, an aneroid barometer can be used to measure altitude.</div>", "topic": "PRESSURE : ATMOSPHERIC PRESSURE"}, {"id": "objective>Physics>2021 Model I>36", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The concept of dispersion of white light into different colours can be explained using </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">reflection</div>", "<div style=\"font-family:Cambria;font-size:17px;\">refraction</div>", "<div style=\"font-family:Cambria;font-size:17px;\">diffraction</div>", "<div style=\"font-family:Cambria;font-size:17px;\">polarization</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Dispersion of light is the splitting or separation of while light into its component colours after passing through a triangular prism. A prism is a refracting material since the light experiences a bending effect after crossing the boundary between two media of different densities i.e air and glass.</div>", "topic": "DISPERSION OF LIGHT AND COLOURS"}, {"id": "objective>Physics>2021 Model I>37", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The effective capacitance in the circuit diagram is  </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">0.60μF</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.75μF</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.20μF</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2.50μF</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">3μF, 6μF and 2μF are in series <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">1<hr size=\"1\" />C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />3</td><td style=\"text-align:center;\">+</td><td style=\"text-align:center;\">1<hr size=\"1\" />6</td><td style=\"text-align:center;\">+</td><td style=\"text-align:center;\">1<hr size=\"1\" />2</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">1<hr size=\"1\" />C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">2 + 1 + 3<hr size=\"1\" />6</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">1<hr size=\"1\" />C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">6<hr size=\"1\" />6</td></tr></table></div> <br/> C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> = 1μF <br/>  <br/> 4μF and 4μF are in series <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">1<hr size=\"1\" />C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />4</td><td style=\"text-align:center;\">+</td><td style=\"text-align:center;\">1<hr size=\"1\" />4</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">1<hr size=\"1\" />C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1+1<hr size=\"1\" />4</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">1<hr size=\"1\" />C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">2<hr size=\"1\" />4</td></tr></table></div> <br/> 2C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = 4 <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">4<hr size=\"1\" />2</td></tr></table></div> <br/> C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = 2μF <br/> C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> and C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> are parallel <br/> C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span> = C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> + C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> <br/> C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span> = 1 + 2 <br/> C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span> = 3μF <br/> 2μF, C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span> and 2μF are in series  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">1<hr size=\"1\" />C</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />2</td><td style=\"text-align:center;\">+</td><td style=\"text-align:center;\">1<hr size=\"1\" />3</td><td style=\"text-align:center;\">+</td><td style=\"text-align:center;\">1<hr size=\"1\" />2</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">1<hr size=\"1\" />C</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">3+2+3<hr size=\"1\" />6</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">1<hr size=\"1\" />C</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">8<hr size=\"1\" />6</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">C</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">6<hr size=\"1\" />8</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">0.75μF</td></tr></table></div> <br/> The effective capacitance is 0.75μF</div>", "topic": "CAPACITORS : CAPACITORS IN SERIES AND PARALLEL"}, {"id": "objective>Physics>2021 Model I>38", "question": "<div style=\"font-family:Cambria;font-size:17px;\">On which of these does the intensity of sound depend?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">harmonics</div>", "<div style=\"font-family:Cambria;font-size:17px;\">overtones</div>", "<div style=\"font-family:Cambria;font-size:17px;\">frequency</div>", "<div style=\"font-family:Cambria;font-size:17px;\">amplitude</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The characteristics of sound are pitch, intensity and timbre (quality). Pitch depends on frequency, intensity depends on loudness or amplitude while timbre depends on overtones and harmonics.</div>", "topic": "CHARACTERISTICS OF SOUND WAVES : QUALITY, PITCH, INTENSITY AND LOUDNESS"}, {"id": "objective>Physics>2021 Model I>39", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The wave property which can be used to differentiate between a sound wave and a light wave is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">reflection</div>", "<div style=\"font-family:Cambria;font-size:17px;\">refraction</div>", "<div style=\"font-family:Cambria;font-size:17px;\">interference </div>", "<div style=\"font-family:Cambria;font-size:17px;\">polarization</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Polarization is a wave property which describes the direction of a wave in space. Only transverse waves can be polarized but longitudinal waves cannot. <br/> Light is a transverse wave while sound is a longitudinal wave.</div>", "topic": "WAVES : CHARACTERISTICS/PROPERTIES"}, {"id": "objective>Physics>2021 Model I>40", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A metre rule of mass 15g pivoted at the 30cm mark balanced horizontally when a mass of 25g was hung at the 18cm mark. If the position of the pivot is moved to the 33cm mark, by how much must the mass be reduced to maintain the horizontal balance of the rule?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">8g</div>", "<div style=\"font-family:Cambria;font-size:17px;\">15g</div>", "<div style=\"font-family:Cambria;font-size:17px;\">17g</div>", "<div style=\"font-family:Cambria;font-size:17px;\">25g</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">It is not specified in the question if the metre rule is uniform. A uniform metre rule has its centre of mass at 50cm, but different for a non-uniform metre rule. <br/> <img src=\"2021 Model I/phy10.png\" style=\"position:relative;max-width:100%;\"/> <br/> Using the principle of moment <br/> Sum of clockwise moment = Sum of anticlockwise moment <br/> 25(30 - 18) = 15(x - 30) <br/> 25 x 12 = 15x - 450 <br/> 300 + 450 = 15x <br/> 750 = 15x <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">x</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">750<hr size=\"1\" />15</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">50cm</td></tr></table></div> <br/> Since the 15g (mass of the metre rule) is at 50cm, that is its centre of mass. <br/> <img src=\"2021 Model I/phy11.png\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> m(33 - 18) = 15(50 - 33) <br/> m x 15 = 15 x 17 <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">m</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">15x17<hr size=\"1\" />15</td></tr></table></div> <br/> m = 17 <br/>  <br/> The difference between the initial and the new mass is 25 - 17 = 8g <br/> ∴ The mass must be reduced by 8g.  </div>", "topic": "EQUILIBRIUM OF FORCES : PRINCIPLES OF MOMENTS"}];
